import 'package:flutter/material.dart';import 'package:go_router/go_router.dart';import '../../core/widgets/empty_view.dart';import '../../core/widgets/loading_view.dart';import '../../services/auth_service.dart';import '../../services/prediction_service.dart';import '../../core/utils/date_time_utils.dart';
class MyPredictionsScreen extends StatelessWidget{const MyPredictionsScreen({super.key});@override Widget build(BuildContext c){if(!AuthService().isLoggedIn)return Scaffold(appBar:AppBar(title:const Text('My Predictions')),body:EmptyView(message:'Login to submit predictions and track your score.',action:Wrap(spacing:8,children:[FilledButton(onPressed:()=>c.go('/login?redirect=/my-predictions'),child:const Text('Login')),OutlinedButton(onPressed:()=>c.go('/register?redirect=/my-predictions'),child:const Text('Register'))])));return Scaffold(appBar:AppBar(title:const Text('My Predictions')),body:FutureBuilder(future:PredictionService().myPredictions(),builder:(c,s){if(s.connectionState==ConnectionState.waiting)return const LoadingView();final list=s.data??[];if(list.isEmpty)return const EmptyView(message:'No predictions yet.');return ListView.builder(itemCount:list.length,itemBuilder:(c,i){final p=list[i];return Card(child:ListTile(title:Text(p.matchTitle),subtitle:Text('${p.teamAName} ${p.teamAScore}-${p.teamBScore} ${p.teamBName}\nScorer: ${p.scorerName??'—'} • ${DateTimeUtils.format(p.submittedAt)}'),trailing:Text(p.points==null?p.status:'${p.points} pts')));});}));}}
